const ARTICLE_DETAILS = {
"artg1": { headline: "The Complete Guide to Dining at Disney Springs", location: "Disney Springs", caption: "Disney Springs has evolved from a shopping mall into one of Orlando's best dining destinations. Whether you're looking for a quick bite between store runs or a full sit-down dinner, there's something for everyone \u2014 and most of it doesn't require a park ticket.", readTime: "8 min", likes: 287, comments: 42, shares: 31, sections: [
{ type: "text", heading: "Quick Service Picks", body: "D-Luxe Burger delivers the best quick service burger outside the parks. The El Diablo burger with pepper jack and jalape\u00f1os is worth the wait. For something lighter, Blaze Pizza lets you build your own for under $12." },
{ type: "image", img: "https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=800&q=80", caption: "The El Diablo burger at D-Luxe Burger" },
{ type: "place", name: "D-Luxe Burger", location: "Disney Springs, FL", img: "https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=200&q=80" },
{ type: "text", heading: "Sit-Down Worth the Reservation", body: "The BOATHOUSE is the anchor. Waterfront dining, excellent seafood, and those amphibious cars are genuinely fun. Wine Bar George is run by a Master Sommelier and the plates are surprisingly generous for the price point." },
{ type: "place", name: "The BOATHOUSE", location: "Disney Springs, FL", img: "https://images.unsplash.com/photo-1555396273-367ea4eb4db5?w=200&q=80" },
{ type: "product", productId: "mg2", note: "If you're spending all day at Disney Springs, this kit has everything you need." },
{ type: "text", heading: "Don't Sleep On", body: "Chef Art Smith's Homecomin' \u2014 the fried chicken is legitimately some of the best in Florida. Morimoto Asia for the sushi. And Gideon's Bakehouse if you're willing to wait in line for a cookie that weighs half a pound." },
{ type: "images", imgs: ["https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=400&q=80", "https://images.unsplash.com/photo-1551024601-bec78aea704b?w=400&q=80"], caption: "Homecomin' fried chicken (left) and Gideon's cookies (right)" },
{ type: "list", listId: "lg1", note: "For the full Magic Kingdom food ranking:" },
{ type: "text", heading: "Skip These", body: "Rainforest Cafe is a tourist trap. T-REX is the same concept with dinosaurs. Planet Hollywood is forgettable. Your money goes further literally everywhere else on the list." },
]},
"artg2": { headline: "Why Rope Drop Changed Everything for Our Family", location: "Magic Kingdom", caption: "We used to show up at 10am and wonder why every ride was a 90-minute wait. Then we tried rope drop once and never went back. Here's exactly how we do it with two kids under 6.", readTime: "5 min", likes: 423, comments: 67, shares: 55, sections: [
{ type: "text", heading: "What Is Rope Drop", body: "Rope drop is getting to the park 30-45 minutes before official opening. Disney often lets guests into Main Street early, and when the rope drops at the entrance to the lands, you walk right onto rides with minimal wait." },
{ type: "image", img: "https://images.unsplash.com/photo-1597466599360-3b9775841aec?w=800&q=80", caption: "Main Street USA before the crowds arrive" },
{ type: "place", name: "Seven Dwarfs Mine Train", location: "Fantasyland, Magic Kingdom", img: "https://images.unsplash.com/photo-1597466599360-3b9775841aec?w=200&q=80" },
{ type: "text", heading: "Our Exact Strategy", body: "Park at 7:15 for an 8am open. Through security by 7:30. On Main Street by 7:45. When the rope drops, we go straight to Seven Dwarfs Mine Train \u2014 walk-on. Then Peter Pan. Then Buzz Lightyear. Three rides done by 8:30." },{ type: "product", productId: "mg1", note: "Essential for early morning park days in the summer heat." },
{ type: "product", productId: "mg3", note: "Your phone will die by noon without this." },
{ type: "text", heading: "Making It Work with Kids", body: "The key is prep the night before. Clothes laid out. Breakfast packed in the car. Kids can sleep in their park outfits if needed. We eat breakfast on Main Street after the first two rides, not before." },
{ type: "experience", name: "VIP After-Hours Tour", price: "$189", userId: 3, img: "https://images.unsplash.com/photo-1597466599360-3b9775841aec?w=400&q=80", note: "If rope drop isn't enough, this tour gives you the park almost empty." },
]},
"artg3": { headline: "Resort Hopping: A Strategy Guide", location: "Walt Disney World", caption: "You don't need to stay at the Grand Floridian to experience it. Resort hopping is free, it's fun, and it's one of the best-kept secrets at Disney World.", readTime: "12 min", likes: 198, comments: 31, shares: 22, sections: [
{ type: "text", heading: "The Monorail Loop", body: "Start at the Transportation & Ticket Center. Take the monorail to the Polynesian Village Resort \u2014 grab a Dole Whip at the stand outside. Walk through the lobby. Then hop back on to the Grand Floridian. The lobby alone is worth the trip." },
{ type: "images", imgs: ["https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=400&q=80", "https://images.unsplash.com/photo-1570213489059-0aac6626cade?w=400&q=80"], caption: "Polynesian Village (left) and the Grand Floridian lobby (right)" },
{ type: "place", name: "Polynesian Village Resort", location: "Bay Lake, FL", img: "https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=200&q=80" },
{ type: "place", name: "Grand Floridian Resort", location: "Bay Lake, FL", img: "https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=200&q=80" },
{ type: "text", heading: "The Skyliner Route", body: "The Skyliner connects Art of Animation, Pop Century, Caribbean Beach, and Riviera. Each resort has its own vibe and dining. Riviera's rooftop bar has the best views of the fireworks you'll find outside the parks." },
{ type: "service", name: "Disney Trip Planning", userId: 1, img: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=400&q=80", note: "Need help planning the perfect resort hopping day?" },
{ type: "text", heading: "Boat Routes", body: "The boats between Magic Kingdom resorts are peaceful and scenic. The Wilderness Lodge boat is particularly beautiful at sunset. Fort Wilderness has Trail's End which is one of the best buffets on property." },
{ type: "image", img: "https://images.unsplash.com/photo-1571896349842-33c89424de2d?w=800&q=80", caption: "Sunset from the Wilderness Lodge boat dock" },
{ type: "text", heading: "Pro Tips", body: "You can eat at any resort restaurant without staying there \u2014 just make a reservation. Parking at resorts requires a dining reservation after 2021 changes. The monorail resorts are the easiest to access without a car." },
{ type: "list", listId: "lg3", note: "More money-saving tips for your trip:" },
{ type: "text", heading: "Best Time to Go", body: "Weekday afternoons are ideal. Resorts are quietest between 10am-4pm when everyone's at the parks. Holiday decorations at resorts start in November and are worth a dedicated day." },
{ type: "product", productId: "mg4", note: "Stay cool while walking between resorts." },
]},
"artg4": { headline: "Navigating Disney with Special Needs Kids", location: "Walt Disney World", caption: "Our daughter has autism and sensory processing disorder. After 12 trips, here's everything we've learned about making Disney work for families like ours.", readTime: "6 min", likes: 567, comments: 93, shares: 78, sections: [
{ type: "text", heading: "DAS (Disability Access Service)", body: "Apply through the My Disney Experience app before your trip. You'll do a video call to explain your child's needs. DAS gives you a return time for rides so you don't wait in the standard queue. It's been a game changer for us." },
{ type: "image", img: "https://images.unsplash.com/photo-1566576912321-d58ddd7a6088?w=800&q=80", caption: "Finding calm moments between attractions" },
{ type: "place", name: "Tom Sawyer Island", location: "Frontierland, Magic Kingdom", img: "https://images.unsplash.com/photo-1597466599360-3b9775841aec?w=200&q=80" },
{ type: "text", heading: "Sensory Tips", body: "Bring noise-canceling headphones \u2014 fireworks, parades, and indoor rides can be overwhelming. Many character interactions can be arranged in quieter settings if you ask at Guest Relations." },
{ type: "product", productId: "mg1", note: "The white noise from the fan helps with sensory overload in crowded areas." },
{ type: "text", heading: "Quiet Spaces", body: "Every park has a first aid station that doubles as a calm-down space. Tom Sawyer Island at Magic Kingdom is naturally quiet. The gardens in Japan Pavilion at EPCOT are our go-to reset spot." },
{ type: "list", listId: "lg2", note: "Our full list of toddler-friendly rides:" },
{ type: "experience", name: "Behind the Seeds Tour", price: "$35", userId: 2, img: "https://images.unsplash.com/photo-1566576912321-d58ddd7a6088?w=400&q=80", note: "Small group, quiet, educational \u2014 perfect for sensory-sensitive kids." },
]},
};
