const extractLocation = (q) => {
const patterns = [
/\bin\s+([A-Z][a-zA-Z\s]+(?:,\s*[A-Z]{2})?)\s*$/i,
/\bnear\s+([A-Z][a-zA-Z\s]+(?:,\s*[A-Z]{2})?)\s*$/i,
/,\s*([A-Z][a-zA-Z\s]+,\s*[A-Z]{2})\s*$/i,
/([A-Z][a-zA-Z\s]+,\s*[A-Z]{2})\s*$/,
];
let _locationResult = null;
patterns.forEach(function(pattern) { if (!_locationResult) { const match = q.match(pattern); if (match) _locationResult = match[1].trim(); } });
if (_locationResult) return _locationResult;
return null;
};const runSearch = (rawQuery) => {
const q = rawQuery.trim();
const ql = q.toLowerCase();
const allUsers = [1,2,3,4,5,6].map(id => getUser(id));
// Exact match checks -- only show card for single confident result
const exactUsers = allUsers.filter(u =>
u.name.toLowerCase() === ql ||
u.handle.toLowerCase() === ql ||
u.handle.toLowerCase() === "@" + ql
);
const closeUsers = exactUsers.length === 0
? allUsers.filter(u => u.name.toLowerCase().includes(ql) || u.handle.toLowerCase().includes(ql))
: [];
const matchedUsers = exactUsers.length === 1 ? exactUsers : closeUsers.length === 1 ? closeUsers : [];
const exactProducts = Object.values(PRODUCT_DETAILS).filter(p => p.name.toLowerCase() === ql);
const closeProducts = exactProducts.length === 0
? Object.values(PRODUCT_DETAILS).filter(p => p.name.toLowerCase().includes(ql))
: [];
const matchedProducts = exactProducts.length === 1 ? exactProducts : closeProducts.length === 1 ? closeProducts : [];
const exactPlaces = PLACES_GRID.filter(p => p.name.toLowerCase() === ql);
const closePlaces = exactPlaces.length === 0
? PLACES_GRID.filter(p => p.name.toLowerCase().includes(ql))
: [];
const matchedPlaces = exactPlaces.length === 1 ? exactPlaces : closePlaces.length === 1 ? closePlaces : [];
const matchedPosts = FEED.filter(p => (p.caption||"").toLowerCase().includes(ql) || (p.place||"").toLowerCase().includes(ql));
// Only attach a card if exactly one confident entity found
const card = matchedUsers.length === 1
? { type: "user", data: matchedUsers[0] }
: matchedProducts.length === 1
? { type: "product", data: matchedProducts[0] }
: matchedPlaces.length === 1
? { type: "place", data: matchedPlaces[0] }
: null;
setActiveSearch({ query: q, card, posts: matchedPosts });
setRecentSearches(prev => [{ id: Date.now(), query: q, type: (card && card.type) || "post" }, ...prev.filter(r => r.query !== q)].slice(0, 8));
setShowSearchPage(false);
setSearchQuery("");
};
