{notif.type === "recommend" && <svg width="10" height="10" viewBox="0 0 24 24" fill="#FFF" stroke="none"><path d="M14 9V5a3 3 0 0 0-3-3l-4 9v11h11.28a2 2 0 0 0 2-1.7l1.38-9a2 2 0 0 0-2-2.3H14z"/></svg>}
