{["Free","Paid"].map(t => (
<button key={t} onClick={() => setEventPrice(t)} style={{ all: "unset", cursor: "pointer", flex: 1, padding: "12px 0", borderRadius: 100, textAlign: "center", background: eventPrice === t ? A.brand : A.bgPage, border: "1.5px solid " + (eventPrice === t ? A.brand : A.border) }}>
<span style={{ fontSize: 14, fontWeight: 700, color: eventPrice === t ? "#FFF" : A.hof, fontFamily: F }}>{t}</span>
</button>
))}
