<button onClick={() => { setShowInvite(false); setShowMenu(true); }} style={{ all: "unset", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", width: 44, height: 44, borderRadius: 40, background: A.bg, boxShadow: "0 2px 8px rgba(0,0,0,0.10), 0 8px 24px rgba(0,0,0,0.12)", border: "0.5px solid " + A.border, flexShrink: 0 }}>
<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={A.dark} strokeWidth="2.5"><path d="M19 12H5M12 19l-7-7 7-7"/></svg>
</button>
