{/* QR Code — same engine as profile QR page */}
{(() => {
const inviteUrl = "drft.app/invite/" + REFERRAL_CODE;
const size = 25; const cellSize = 8; const qrSize = size * cellSize;
const logoSize = 48; const pad = 16;
let seed = 0;
for (let i = 0; i < inviteUrl.length; i++) seed = ((seed << 5) - seed + inviteUrl.charCodeAt(i)) | 0;
const rng = () => { seed = (seed * 16807) % 2147483647; return seed / 2147483647; };
const grid = [];
for (let y = 0; y < size; y++) {
const row = [];
for (let x = 0; x < size; x++) {
const inTL = x < 7 && y < 7;
const inTR = x >= size - 7 && y < 7;
const inBL = x < 7 && y >= size - 7;
if (inTL || inTR || inBL) {
const cx = inTL ? 3 : inTR ? size - 4 : 3;
const cy = inTL ? 3 : inTR ? 3 : size - 4;
const ring = Math.max(Math.abs(x - cx), Math.abs(y - cy));
row.push(ring <= 1 || ring === 3 ? 1 : 0);
} else if (y === 6 || x === 6) {
row.push((x + y) % 2 === 0 ? 1 : 0);
} else {
row.push(rng() > 0.5 ? 1 : 0);
}
}
grid.push(row);
}
const centerStart = (qrSize - logoSize) / 2 - 8;
const centerEnd = (qrSize + logoSize) / 2 + 8;
const boxSize = qrSize + pad * 2;
return (
<div style={{ position: "relative", width: boxSize, height: boxSize, background: "#FFF", borderRadius: 20, marginBottom: 24, flexShrink: 0 }}>
<svg width={qrSize} height={qrSize} viewBox={"0 0 " + qrSize + " " + qrSize} style={{ position: "absolute", top: pad, left: pad }}>
{grid.map((row, y) => row.map((cell, x) => {
const px = x * cellSize; const py = y * cellSize;
if (px >= centerStart && px + cellSize <= centerEnd && py >= centerStart && py + cellSize <= centerEnd) return null;
return cell ? <rect key={x + "-" + y} x={px} y={py} width={cellSize - 1} height={cellSize - 1} rx={2} fill={A.brand} /> : null;
}))}
</svg>
<div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%,-50%)", width: logoSize, height: logoSize, borderRadius: 14, background: "#FFF", display: "flex", alignItems: "center", justifyContent: "center" }}>
<div style={{ width: logoSize - 6, height: logoSize - 6, borderRadius: 12, background: A.brand, display: "flex", alignItems: "center", justifyContent: "center" }}>
<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="#FFF" strokeWidth="2.5" strokeLinecap="round"><path d="M12 2L2 7l10 5 10-5-10-5z"/><path d="M2 17l10 5 10-5"/><path d="M2 12l10 5 10-5"/></svg>
</div>
</div>
</div>
);
})()}
