<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={A.brand} strokeWidth="2.5"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
