<span style={{ fontSize: 14, color: newListingCategory ? A.dark : A.foggy, fontFamily: F, fontWeight: newListingCategory ? 600 : 400 }}>{newListingCategory || (newListingType ? "Select a category" : "Select a listing type first")}</span>
