<div>
<div style={{ fontSize: 12, fontWeight: 700, color: A.dark, fontFamily: F, marginBottom: 6, textTransform: "uppercase", letterSpacing: 0.5 }}>Description</div>
<textarea value={newListingDesc} onChange={e => setNewListingDesc(e.target.value)} placeholder="Describe it — condition, details, what's included..." rows={4} style={{ all: "unset", display: "block", width: "100%", padding: "13px 14px", borderRadius: 12, background: A.bg, border: "1px solid " + (newListingDesc ? A.brand : A.border), fontSize: 14, color: A.dark, fontFamily: F, boxSizing: "border-box", lineHeight: 1.55, resize: "none" }} />
</div>
{/* 6 — Features */}
<div>
<div style={{ fontSize: 12, fontWeight: 700, color: A.dark, fontFamily: F, marginBottom: 6, textTransform: "uppercase", letterSpacing: 0.5 }}>Features</div>
<div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
{(newListingFeatures ? newListingFeatures.split("\n") : [""]).map((feat, fi) => (
<div key={fi} style={{ display: "flex", alignItems: "center", gap: 8 }}>
<input value={feat} onChange={e => { const arr = newListingFeatures ? newListingFeatures.split("\n") : [""]; arr[fi] = e.target.value; setNewListingFeatures(arr.join("\n")); }} placeholder={`Feature ${fi + 1}`} style={{ all: "unset", flex: 1, padding: "13px 14px", borderRadius: 12, background: A.bg, border: "1px solid " + (feat ? A.brand : A.border), fontSize: 14, color: A.dark, fontFamily: F, boxSizing: "border-box" }} />
{(newListingFeatures ? newListingFeatures.split("\n") : [""]).length > 1 && (
<button onClick={() => { const arr = newListingFeatures.split("\n"); arr.splice(fi, 1); setNewListingFeatures(arr.join("\n")); }} style={{ all: "unset", cursor: "pointer", width: 32, height: 32, borderRadius: "50%", background: A.bgPage, border: "1px solid " + A.border, display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
<svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke={A.foggy} strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
</button>
)}
</div>
))}
{(newListingFeatures ? newListingFeatures.split("\n") : [""]).length < 6 && (
<button onClick={() => setNewListingFeatures(prev => (prev || "") + (prev ? "\n" : "") + "")} style={{ all: "unset", cursor: "pointer", width: "100%", padding: "13px 0", borderRadius: 12, background: A.bgPage, border: "1.5px dashed " + A.border, textAlign: "center", boxSizing: "border-box" }}>
<span style={{ fontSize: 14, fontWeight: 600, color: A.brand, fontFamily: F }}>+ Add Feature</span>
</button>
)}
</div>
</div>
{/* 7 — Price */}
<div>
<div style={{ fontSize: 12, fontWeight: 700, color: A.dark, fontFamily: F, marginBottom: 6, textTransform: "uppercase", letterSpacing: 0.5 }}>Price</div>
<div style={{ position: "relative" }}>
<span style={{ position: "absolute", left: 14, top: "50%", transform: "translateY(-50%)", fontSize: 14, fontWeight: 600, color: newListingPrice ? A.dark : A.foggy, fontFamily: F, pointerEvents: "none" }}>$</span>
<input value={newListingPrice} onChange={e => { const raw = e.target.value.replace(/[^0-9.]/g, "").replace(/^(\d*\.?\d{0,2}).*/,"$1"); setNewListingPrice(raw); }} onBlur={() => { if (newListingPrice) { const n = parseFloat(newListingPrice); if (!isNaN(n)) { const [whole, dec] = n.toFixed(2).split("."); setNewListingPrice(Number(whole).toLocaleString("en-US") + "." + dec); } } }} onFocus={() => { if (newListingPrice) setNewListingPrice(newListingPrice.replace(/,/g, "")); }} placeholder="0.00" inputMode="decimal" style={{ all: "unset", display: "block", width: "100%", padding: "13px 14px 13px 26px", borderRadius: 12, background: A.bg, border: "1px solid " + (newListingPrice ? A.brand : A.border), fontSize: 14, color: A.dark, fontFamily: F, boxSizing: "border-box" }} />
</div>
</div>
